+            variants_seen.insert(2);
+        } else if case.source.contains('+') {
+            variants_seen.insert(4);
+        } else if case.source.contains(";\n") {
+            variants_seen.insert(5);
+        }
+    }
+    // At least several distinct variant shapes should be produced
+    assert!(
+        variants_seen.len() >= 3,
